import java.io.*;

public class Main {
    private static class FastScanner {
        private final InputStream in;
        private final byte[] buffer = new byte[1 << 16];
        private int ptr = 0, len = 0;
        FastScanner(InputStream in) { this.in = in; }
        private int read() throws IOException {
            if (ptr >= len) {
                len = in.read(buffer);
                ptr = 0;
                if (len <= 0) return -1;
            }
            return buffer[ptr++];
        }
        int nextInt() throws IOException {
            int c;
            // skip any character that is not '-' or a digit
            do {
                c = read();
                if (c == -1) return Integer.MIN_VALUE; // EOF
            } while (c != '-' && (c < '0' || c > '9'));
            int sign = 1;
            if (c == '-') {
                sign = -1;
                c = read();
            }
            int val = 0;
            while (c >= '0' && c <= '9') {
                val = val * 10 + (c - '0');
                c = read();
            }
            return val * sign;
        }
        long nextLong() throws IOException {
            int c;
            do {
                c = read();
                if (c == -1) return Long.MIN_VALUE;
            } while (c != '-' && (c < '0' || c > '9'));
            int sign = 1;
            if (c == '-') {
                sign = -1;
                c = read();
            }
            long val = 0;
            while (c >= '0' && c <= '9') {
                val = val * 10 + (c - '0');
                c = read();
            }
            return sign == 1 ? val : -val;
        }
    }
    public static void main(String[] args) throws Exception {
        FastScanner fs = new FastScanner(System.in);
        StringBuilder out = new StringBuilder();
        int T = fs.nextInt();
        for (int t = 0; t < T; t++) {
            int N = fs.nextInt();
            long[] A = new long[N];
            for (int i = 0; i < N; i++) {
                A[i] = fs.nextLong();
            }
            int[] ans = new int[N];
            ans[N - 1] = 1;
            for (int i = N - 2; i >= 0; --i) {
                if (A[i] * A[i + 1] < 0) ans[i] = ans[i + 1] + 1;
                else ans[i] = 1;
            }
            for (int i = 0; i < N; ++i) {
                if (i > 0) out.append(' ');
                out.append(ans[i]);
            }
            out.append('\n');
        }
        System.out.print(out.toString());
    }
}

